// Fire-and-forget 3D sound
UGameplayStatics::PlaySoundAtLocation(this, FireSound, GetActorLocation());

// 2D UI sound
UGameplayStatics::PlaySound2D(this, ButtonClickSound);

// Persistent audio component
UPROPERTY(VisibleAnywhere)
UAudioComponent* EngineAudioComp;

AMyCar::AMyCar() {
    EngineAudioComp = CreateDefaultSubobject<UAudioComponent>(TEXT("EngineAudio"));
    EngineAudioComp->SetupAttachment(RootComponent);
    EngineAudioComp->bAutoActivate = true;
}

// Control at runtime
EngineAudioComp->SetFloatParameter(TEXT("RPM"), CurrentRPM);
EngineAudioComp->SetVolumeMultiplier(0.5f);
EngineAudioComp->Stop();
EngineAudioComp->Play();

// Playing a MetaSound and controlling parameters
UPROPERTY(EditAnywhere)
USoundBase* EngineMetaSound; // Can be a MetaSoundSource

UAudioComponent* AudioComp = UGameplayStatics::SpawnSoundAttached(
    EngineMetaSound, GetRootComponent()
);

// Set parameters at runtime
AudioComp->SetFloatParameter(TEXT("RPM"), CurrentRPM);
AudioComp->SetFloatParameter(TEXT("Load"), ThrottlePercent);
AudioComp->SetBoolParameter(TEXT("bTurboActive"), bTurboOn);

// Fire a one-shot trigger
AudioComp->SetTriggerParameter(TEXT("OnGearShift"));

// Volume settings from options menu
void UMyAudioManager::SetMusicVolume(float Volume) {
    // Option 1: Sound Mix override
    UGameplayStatics::SetSoundMixClassOverride(
        GetWorld(), MainSoundMix, MusicSoundClass,
        Volume,  // Volume
        1.0f,    // Pitch
        0.5f     // Fade time
    );
    UGameplayStatics::PushSoundMixModifier(GetWorld(), MainSoundMix);
}

// Option 2: Direct class volume (simpler)
void UMyAudioManager::SetSFXVolume(float Volume) {
    if (FAudioDevice* AudioDevice = GetWorld()->GetAudioDevice().GetAudioDevice()) {
        AudioDevice->SetClassVolume(SFXSoundClass, Volume);
    }
}
